import React, { useState, useEffect } from 'react';
import { Search, Filter, TrendingUp, Calendar, Star, Trash2, Eye, BarChart3, User, Film, Grid, List, Trophy, Clock, Heart } from 'lucide-react';

// Mock components and services for demo
const Link = ({ to, children, className, ...props }) => (
  <a href={to} className={className} {...props} onClick={(e) => e.preventDefault()}>{children}</a>
);

const AuthContext = React.createContext({ user: { name: 'John Doe', id: 1 } });
const useContext = React.useContext;

const getMyRatings = async ({ page, limit }) => {
  const mockMovies = [
    { title: 'The Dark Knight', year: 2008, genre: 'Action' },
    { title: 'Inception', year: 2010, genre: 'Sci-Fi' },
    { title: 'Pulp Fiction', year: 1994, genre: 'Crime' },
    { title: 'The Shawshank Redemption', year: 1994, genre: 'Drama' },
    { title: 'Fight Club', year: 1999, genre: 'Drama' },
    { title: 'The Matrix', year: 1999, genre: 'Sci-Fi' },
    { title: 'Interstellar', year: 2014, genre: 'Sci-Fi' },
    { title: 'Goodfellas', year: 1990, genre: 'Crime' },
    { title: 'The Godfather', year: 1972, genre: 'Crime' },
    { title: 'Parasite', year: 2019, genre: 'Thriller' },
    { title: 'Spirited Away', year: 2001, genre: 'Animation' },
    { title: 'Your Name', year: 2016, genre: 'Animation' }
  ];

  return {
    ratings: Array.from({ length: Math.min(12, mockMovies.length) }, (_, i) => ({
      movie_id: i + 1,
      movie_title: mockMovies[i].title,
      movie_year: mockMovies[i].year,
      genre: mockMovies[i].genre,
      rating: Math.round((2.5 + Math.random() * 2.5) * 10) / 10,
      timestamp: new Date(2024 - Math.floor(Math.random() * 2), Math.floor(Math.random() * 12), Math.floor(Math.random() * 28) + 1).toISOString(),
      review: Math.random() > 0.5 ? [
        'Absolutely phenomenal! The cinematography was breathtaking and the story kept me on the edge of my seat.',
        'A masterpiece of storytelling. Every scene was perfectly crafted and the performances were outstanding.',
        'Incredible visual effects and emotional depth. This movie will stay with me for a long time.',
        'Pure genius! The director\'s vision was executed flawlessly and the soundtrack was perfect.',
        'Mind-bending and thought-provoking. I loved every minute of this cinematic experience.'
      ][Math.floor(Math.random() * 5)] : null,
      poster_url: `https://picsum.photos/300/450?random=${i + 20}`
    }))
  };
};

const MyRatingsPage = () => {
  const { user } = useContext(AuthContext);
  const [ratings, setRatings] = useState([]);
  const [filteredRatings, setFilteredRatings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [sortBy, setSortBy] = useState('newest');
  const [filterRating, setFilterRating] = useState('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [deleteLoading, setDeleteLoading] = useState(null);
  const [viewMode, setViewMode] = useState('grid');
  const [showFilters, setShowFilters] = useState(false);

  useEffect(() => {
    if (user) {
      fetchRatings();
    }
  }, [user]);

  useEffect(() => {
    applyFiltersAndSort();
  }, [ratings, sortBy, filterRating, searchQuery]);

  const fetchRatings = async () => {
    setLoading(true);
    try {
      const data = await getMyRatings({ page: 1, limit: 20 });
      setRatings(data.ratings);
    } catch (error) {
      setError('Failed to load your ratings. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const applyFiltersAndSort = () => {
    let filtered = [...ratings];

    if (searchQuery.trim()) {
      filtered = filtered.filter(rating =>
        rating.movie_title.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }

    if (filterRating !== 'all') {
      const ratingValue = parseInt(filterRating);
      filtered = filtered.filter(rating => Math.floor(rating.rating) === ratingValue);
    }

    filtered.sort((a, b) => {
      switch (sortBy) {
        case 'newest': return new Date(b.timestamp) - new Date(a.timestamp);
        case 'oldest': return new Date(a.timestamp) - new Date(b.timestamp);
        case 'highest': return b.rating - a.rating;
        case 'lowest': return a.rating - b.rating;
        case 'title': return a.movie_title.localeCompare(b.movie_title);
        case 'year': return b.movie_year - a.movie_year;
        default: return 0;
      }
    });

    setFilteredRatings(filtered);
  };

  const handleDeleteRating = async (movieId, movieTitle) => {
    if (!window.confirm(`Delete rating for "${movieTitle}"?`)) return;

    setDeleteLoading(movieId);
    try {
      await new Promise(resolve => setTimeout(resolve, 1000));
      setRatings(prev => prev.filter(rating => rating.movie_id !== movieId));
    } catch (error) {
      console.error('Error deleting rating:', error);
    } finally {
      setDeleteLoading(null);
    }
  };

  const renderStars = (rating) => {
    const fullStars = Math.floor(rating);
    const hasHalfStar = rating % 1 >= 0.5;
    const emptyStars = 5 - fullStars - (hasHalfStar ? 1 : 0);

    return (
      <div className="flex items-center gap-0.5">
        {[...Array(fullStars)].map((_, i) => (
          <Star key={i} className="w-4 h-4 fill-amber-400 text-amber-400" />
        ))}
        {hasHalfStar && <Star className="w-4 h-4 fill-amber-400/50 text-amber-400" />}
        {[...Array(emptyStars)].map((_, i) => (
          <Star key={`empty-${i}`} className="w-4 h-4 text-gray-300" />
        ))}
      </div>
    );
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  };

  const getRatingColor = (rating) => {
    if (rating >= 4.5) return 'from-emerald-500 to-green-500';
    if (rating >= 3.5) return 'from-lime-500 to-green-500';
    if (rating >= 2.5) return 'from-amber-500 to-orange-500';
    if (rating >= 1.5) return 'from-orange-500 to-red-500';
    return 'from-red-500 to-red-600';
  };

  const getStatistics = () => {
    if (ratings.length === 0) return null;
    const totalRatings = ratings.length;
    const avgRating = ratings.reduce((sum, r) => sum + r.rating, 0) / totalRatings;
    const ratingCounts = ratings.reduce((acc, r) => {
      const star = Math.floor(r.rating);
      acc[star] = (acc[star] || 0) + 1;
      return acc;
    }, {});
    return { totalRatings, avgRating, ratingCounts };
  };

  if (!user) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-900 via-purple-900 to-slate-900 flex items-center justify-center p-4">
        <div className="bg-white/10 backdrop-blur-xl rounded-3xl shadow-2xl p-12 text-center max-w-md border border-white/20">
          <div className="w-20 h-20 mx-auto mb-6 bg-gradient-to-r from-purple-400 to-pink-400 rounded-full flex items-center justify-center">
            <User className="w-10 h-10 text-white" />
          </div>
          <h2 className="text-3xl font-bold text-white mb-4">Welcome Back!</h2>
          <p className="text-gray-300 mb-8 leading-relaxed">Sign in to view your movie ratings and discover your viewing patterns.</p>
          <Link 
            to="/login" 
            className="inline-flex items-center gap-2 bg-gradient-to-r from-purple-500 to-pink-500 text-white px-8 py-4 rounded-2xl font-semibold hover:from-purple-600 hover:to-pink-600 transform hover:scale-105 transition-all duration-200 shadow-lg hover:shadow-xl"
          >
            Sign In Now
          </Link>
        </div>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-900 via-purple-900 to-slate-900 flex items-center justify-center">
        <div className="text-center">
          <div className="relative">
            <div className="w-16 h-16 border-4 border-purple-500/30 rounded-full animate-spin border-t-purple-500 mx-auto mb-4"></div>
            <Film className="w-6 h-6 text-purple-400 absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2" />
          </div>
          <p className="text-lg text-gray-300">Loading your cinematic journey...</p>
        </div>
      </div>
    );
  }

  const stats = getStatistics();

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-purple-900 to-slate-900">
      <div className="max-w-7xl mx-auto px-4 py-12">
        {/* Animated Header */}
        <div className="text-center mb-16 relative">
          <div className="absolute inset-0 bg-gradient-to-r from-purple-600/20 to-pink-600/20 rounded-full blur-3xl transform scale-150"></div>
          <div className="relative">
            <div className="inline-flex items-center gap-4 mb-6">
              <div className="w-16 h-16 bg-gradient-to-r from-purple-500 to-pink-500 rounded-2xl flex items-center justify-center transform rotate-3 hover:rotate-0 transition-transform duration-300">
                <BarChart3 className="w-8 h-8 text-white" />
              </div>
              <h1 className="text-6xl font-bold bg-gradient-to-r from-white via-purple-100 to-pink-100 bg-clip-text text-transparent">
                My Cinema
              </h1>
            </div>
            <p className="text-xl text-gray-300 mb-8">Your personal movie rating collection</p>

            {stats && (
              <div className="flex items-center justify-center gap-8 mt-12">
                <div className="group bg-white/10 backdrop-blur-lg rounded-2xl px-8 py-6 border border-white/20 hover:bg-white/20 transition-all duration-300 transform hover:-translate-y-1">
                  <div className="text-4xl font-bold text-white mb-1">{stats.totalRatings}</div>
                  <div className="text-sm text-gray-300 font-medium flex items-center gap-1">
                    <Film className="w-4 h-4" />
                    Movies Rated
                  </div>
                </div>
                <div className="group bg-white/10 backdrop-blur-lg rounded-2xl px-8 py-6 border border-white/20 hover:bg-white/20 transition-all duration-300 transform hover:-translate-y-1">
                  <div className="text-4xl font-bold text-white mb-1">{stats.avgRating.toFixed(1)}</div>
                  <div className="text-sm text-gray-300 font-medium flex items-center gap-1">
                    <Star className="w-4 h-4 fill-amber-400 text-amber-400" />
                    Average Rating
                  </div>
                </div>
                <div className="group bg-white/10 backdrop-blur-lg rounded-2xl px-8 py-6 border border-white/20 hover:bg-white/20 transition-all duration-300 transform hover:-translate-y-1">
                  <div className="text-4xl font-bold text-white mb-1">
                    {Math.max(...Object.keys(stats.ratingCounts).map(Number)) || 0}
                  </div>
                  <div className="text-sm text-gray-300 font-medium flex items-center gap-1">
                    <Trophy className="w-4 h-4 text-yellow-400" />
                    Top Rating
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>

        {error && (
          <div className="bg-red-500/10 border border-red-500/30 rounded-2xl p-6 mb-8 backdrop-blur-lg">
            <div className="flex items-center gap-3 mb-4">
              <div className="w-10 h-10 bg-red-500/20 rounded-full flex items-center justify-center">
                <span className="text-red-400">⚠</span>
              </div>
              <p className="text-red-300 font-medium">{error}</p>
            </div>
            <button 
              onClick={fetchRatings}
              className="bg-red-500 hover:bg-red-600 text-white px-6 py-2 rounded-xl transition-colors"
            >
              Try Again
            </button>
          </div>
        )}

        {ratings.length > 0 ? (
          <>
            {/* Enhanced Search & Controls */}
            <div className="bg-white/10 backdrop-blur-xl rounded-3xl shadow-2xl p-8 mb-12 border border-white/20">
              {/* Search Bar */}
              <div className="relative mb-8">
                <div className="absolute left-6 top-1/2 transform -translate-y-1/2 text-gray-400">
                  <Search className="w-6 h-6" />
                </div>
                <input
                  type="text"
                  placeholder="Search your movie collection..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full pl-14 pr-6 py-5 bg-white/10 backdrop-blur-lg border border-white/20 rounded-2xl focus:outline-none focus:ring-4 focus:ring-purple-500/30 focus:border-purple-400/50 transition-all text-white placeholder-gray-400 text-lg"
                />
              </div>

              {/* Controls */}
              <div className="flex flex-wrap items-center justify-between gap-6">
                <div className="flex items-center gap-6">
                  <button
                    onClick={() => setShowFilters(!showFilters)}
                    className="flex items-center gap-2 bg-white/10 hover:bg-white/20 border border-white/20 text-white px-4 py-2 rounded-xl transition-all"
                  >
                    <Filter className="w-5 h-5" />
                    Filters
                  </button>

                  <div className="flex items-center gap-3 bg-white/10 rounded-xl p-1">
                    <TrendingUp className="w-5 h-5 text-gray-300 ml-3" />
                    <select
                      value={sortBy}
                      onChange={(e) => setSortBy(e.target.value)}
                      className="bg-transparent border-none text-white focus:outline-none pr-8"
                    >
                      <option value="newest" className="bg-slate-800">Newest First</option>
                      <option value="oldest" className="bg-slate-800">Oldest First</option>
                      <option value="highest" className="bg-slate-800">Highest Rated</option>
                      <option value="lowest" className="bg-slate-800">Lowest Rated</option>
                      <option value="title" className="bg-slate-800">Movie Title</option>
                      <option value="year" className="bg-slate-800">Release Year</option>
                    </select>
                  </div>

                  {showFilters && (
                    <div className="flex items-center gap-3 bg-white/10 rounded-xl p-1 animate-fade-in">
                      <Star className="w-5 h-5 text-amber-400 ml-3" />
                      <select
                        value={filterRating}
                        onChange={(e) => setFilterRating(e.target.value)}
                        className="bg-transparent border-none text-white focus:outline-none pr-8"
                      >
                        <option value="all" className="bg-slate-800">All Ratings</option>
                        <option value="5" className="bg-slate-800">5 Stars</option>
                        <option value="4" className="bg-slate-800">4 Stars</option>
                        <option value="3" className="bg-slate-800">3 Stars</option>
                        <option value="2" className="bg-slate-800">2 Stars</option>
                        <option value="1" className="bg-slate-800">1 Star</option>
                      </select>
                    </div>
                  )}
                </div>

                <div className="flex items-center gap-2 bg-white/10 rounded-xl p-1">
                  <button
                    onClick={() => setViewMode('grid')}
                    className={`p-3 rounded-lg transition-all ${viewMode === 'grid' ? 'bg-purple-500 text-white' : 'text-gray-300 hover:text-white'}`}
                  >
                    <Grid className="w-5 h-5" />
                  </button>
                  <button
                    onClick={() => setViewMode('list')}
                    className={`p-3 rounded-lg transition-all ${viewMode === 'list' ? 'bg-purple-500 text-white' : 'text-gray-300 hover:text-white'}`}
                  >
                    <List className="w-5 h-5" />
                  </button>
                </div>
              </div>
            </div>

            {/* Enhanced Statistics */}
            {stats && (
              <div className="bg-white/10 backdrop-blur-xl rounded-3xl shadow-2xl p-8 mb-12 border border-white/20">
                <h3 className="text-2xl font-bold text-white mb-8 flex items-center gap-3">
                  <BarChart3 className="w-6 h-6 text-purple-400" />
                  Rating Distribution
                </h3>
                <div className="space-y-6 max-w-3xl">
                  {[5, 4, 3, 2, 1].map(star => (
                    <div key={star} className="flex items-center gap-6">
                      <div className="flex items-center gap-2 w-20">
                        <span className="font-bold text-white text-lg">{star}</span>
                        <Star className="w-5 h-5 fill-amber-400 text-amber-400" />
                      </div>
                      <div className="flex-1 h-4 bg-white/10 rounded-full overflow-hidden">
                        <div
                          className={`h-full rounded-full transition-all duration-1000 bg-gradient-to-r ${getRatingColor(star)}`}
                          style={{
                            width: `${stats.ratingCounts[star] ? (stats.ratingCounts[star] / stats.totalRatings) * 100 : 0}%`,
                          }}
                        ></div>
                      </div>
                      <span className="font-bold text-gray-300 w-12 text-right text-lg">
                        {stats.ratingCounts[star] || 0}
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Movies Grid/List */}
            <div className={`mb-12 ${
              viewMode === 'grid' 
                ? 'grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8' 
                : 'space-y-6'
            }`}>
              {filteredRatings.length > 0 ? (
                filteredRatings.map((rating) => (
                  <div 
                    key={rating.movie_id} 
                    className={`group bg-white/10 backdrop-blur-lg rounded-3xl shadow-xl hover:shadow-2xl border border-white/20 overflow-hidden transition-all duration-500 hover:-translate-y-2 hover:bg-white/20 ${
                      viewMode === 'list' ? 'flex items-center' : ''
                    }`}
                  >
                    {/* Movie Poster */}
                    <div className={`relative overflow-hidden ${
                      viewMode === 'list' ? 'w-32 h-48 flex-shrink-0' : 'h-80'
                    }`}>
                      <img
                        src={rating.poster_url}
                        alt={rating.movie_title}
                        className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
                      />
                      <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent"></div>
                      <div className="absolute top-4 right-4">
                        <div className={`bg-gradient-to-r ${getRatingColor(rating.rating)} text-white px-3 py-1 rounded-full font-bold text-sm shadow-lg`}>
                          {rating.rating}
                        </div>
                      </div>
                    </div>

                    {/* Content */}
                    <div className="p-6 flex-1">
                      <div className="flex items-start justify-between mb-4">
                        <div>
                          <Link 
                            to={`/movies/${rating.movie_id}`}
                            className="text-xl font-bold text-white hover:text-purple-300 transition-colors group-hover:text-purple-200"
                          >
                            {rating.movie_title}
                          </Link>
                          <div className="flex items-center gap-3 mt-1">
                            <span className="text-gray-400">({rating.movie_year})</span>
                            <span className="text-purple-300 text-sm bg-purple-500/20 px-2 py-1 rounded-full">
                              {rating.genre}
                            </span>
                          </div>
                        </div>
                      </div>

                      <div className="flex items-center gap-3 mb-4">
                        {renderStars(rating.rating)}
                        <span className="text-white font-semibold">{rating.rating}/5</span>
                      </div>

                      <div className="flex items-center gap-2 text-sm text-gray-300 mb-4">
                        <Clock className="w-4 h-4" />
                        Rated on {formatDate(rating.timestamp)}
                      </div>

                      {rating.review && (
                        <div className="bg-purple-500/10 border border-purple-500/20 rounded-2xl p-4 mb-6">
                          <div className="flex items-center gap-2 mb-2">
                            <Heart className="w-4 h-4 text-purple-400" />
                            <span className="text-purple-300 font-medium text-sm">Your Review</span>
                          </div>
                          <p className="text-gray-300 italic leading-relaxed">"{rating.review}"</p>
                        </div>
                      )}

                      <div className="flex items-center gap-3">
                        <Link
                          to={`/movies/${rating.movie_id}`}
                          className="flex items-center gap-2 bg-gradient-to-r from-purple-500 to-pink-500 hover:from-purple-600 hover:to-pink-600 text-white px-4 py-2 rounded-xl font-medium transition-all transform hover:scale-105 shadow-lg"
                        >
                          <Eye className="w-4 h-4" />
                          View
                        </Link>
                        <button
                          onClick={() => handleDeleteRating(rating.movie_id, rating.movie_title)}
                          disabled={deleteLoading === rating.movie_id}
                          className="flex items-center gap-2 bg-red-500/20 hover:bg-red-500/30 border border-red-500/30 text-red-300 px-4 py-2 rounded-xl font-medium transition-all disabled:opacity-50"
                        >
                          <Trash2 className="w-4 h-4" />
                          {deleteLoading === rating.movie_id ? 'Deleting...' : 'Delete'}
                        </button>
                      </div>
                    </div>
                  </div>
                ))
              ) : (
                <div className="col-span-full bg-white/10 backdrop-blur-xl rounded-3xl shadow-2xl p-16 text-center border border-white/20">
                  <Film className="w-20 h-20 mx-auto mb-6 text-gray-400" />
                  <h3 className="text-3xl font-bold text-white mb-4">No movies found</h3>
                  <p className="text-gray-300 text-lg">
                    {searchQuery 
                      ? `No movies match "${searchQuery}"` 
                      : filterRating !== 'all' 
                        ? `No ${filterRating}-star movies found` 
                        : 'No ratings to show'
                    }
                  </p>
                </div>
              )}
            </div>
          </>
        ) : (
          <div className="bg-white/10 backdrop-blur-xl rounded-3xl shadow-2xl p-20 text-center border border-white/20">
            <div className="relative mb-8">
              <div className="w-32 h-32 mx-auto bg-gradient-to-r from-purple-500/20 to-pink-500/20 rounded-full flex items-center justify-center">
                <Film className="w-16 h-16 text-purple-400" />
              </div>
              <div className="absolute -top-2 -right-2 w-8 h-8 bg-gradient-to-r from-purple-500 to-pink-500 rounded-full flex items-center justify-center animate-bounce">
                <span className="text-white font-bold">+</span>
              </div>
            </div>
            <h3 className="text-4xl font-bold text-white mb-6">Start Your Cinema Journey</h3>
            <p className="text-xl text-gray-300 mb-12 max-w-2xl mx-auto leading-relaxed">
              Rate your favorite movies and build a personalized collection that reflects your unique taste in cinema.
            </p>
            <div className="flex items-center justify-center gap-6">
              <Link 
                to="/movies" 
                className="flex items-center gap-3 bg-gradient-to-r from-purple-500 to-pink-500 hover:from-purple-600 hover:to-pink-600 text-white px-8 py-4 rounded-2xl font-semibold transition-all transform hover:scale-105 shadow-lg hover:shadow-xl"
              >
                <Film className="w-5 h-5" />
                Browse Movies
              </Link>
              <Link 
                to="/recommendations" 
                className="flex items-center gap-3 bg-white/10 hover:bg-white/20 border border-white/20 text-white px-8 py-4 rounded-2xl font-semibold transition-all transform hover:scale-105 backdrop-blur-lg"
              >
                <TrendingUp className="w-5 h-5" />
                Popular Movies
              </Link>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default MyRatingsPage;
